prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type ?parent WHERE {
  ?elem tai:belongsTo+ <https://www.teamingai-project.eu/kg/model/sid_e10a5cbc_c283_4709_86cd_d5009481692d> .
  ?elem a ?type .
  FILTER(?type = bboExt:Message)
  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem tai:belongsTo ?parent . }
}
LIMIT 25
